+/**
+ * Order validators — pure validation functions for order business rules.
+ *
+ * All functions are pure: no side effects, no database calls.
+ * Services call these after fetching data from repositories.
+ */
+
+import type { OrderItem, OrderStatus } from '../models/order.js';
+
+/**
+ * Valid order status transitions (state machine).
+ */
+export const ORDER_STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
+  pending: ['confirmed', 'cancelled'],
+  confirmed: ['shipped', 'cancelled'],
+  shipped: ['delivered'],
+  delivered: [],
+  cancelled: [],
+};
+
+/**
+ * Check whether a status transition is allowed.
+ */
+export function isValidStatusTransition(
+  from: OrderStatus,
+  to: OrderStatus,
+): boolean {
+  return ORDER_STATUS_TRANSITIONS[from].includes(to);
+}
+
+/**
+ * Validate that a status transition is allowed. Throws if not.
+ */
+export function validateStatusTransition(
+  from: OrderStatus,
+  to: OrderStatus,
+): void {
+  if (!isValidStatusTransition(from, to)) {
+    throw new Error(`Invalid status transition: ${from} -> ${to}`);
+  }
+}
+
+/**
+ * Validate that an order has at least one item.
+ */
+export function validateOrderHasItems(items: OrderItem[]): void {
+  if (items.length === 0) {
+    throw new Error('Order must have at least one item');
+  }
+}
+
+/**
+ * Validate that a user exists (for order creation).
+ * Takes the lookup result — the repository call stays in the service.
+ */
+export function validateUserForOrder<T extends { id: string }>(
+  user: T | undefined,
+  userId: string,
+): asserts user is T {
+  if (!user) {
+    throw new Error(`User not found: ${userId}`);
+  }
+}

