/**
 * Order validators — pure validation functions for order business rules.
 *
 * All functions are pure: no side effects, no database calls.
 * Services call these after fetching data from repositories.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';

/**
 * Valid order status transitions (state machine).
 */
export const ORDER_STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return ORDER_STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed. Throws if not.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate that an order has at least one item.
 */
export function validateOrderHasItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Validate that a user exists (for order creation).
 * Takes the lookup result — the repository call stays in the service.
 */
export function validateUserForOrder(
  user: { id: string } | undefined,
  userId: string,
): void {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * User validators — pure validation functions for user business rules.
 *
 * All functions are pure: no side effects, no database calls.
 * Services call these after fetching data from repositories.
 */

import type { User } from '../models/user.js';

/**
 * Validate that an email is not already taken by another user.
 * Used during user creation.
 */
export function validateEmailNotTaken(
  existingUser: User | undefined,
  email: string,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not in use by a different user.
 * Used during user update when the email is being changed.
 */
export function validateEmailNotInUse(
  existingUser: User | undefined,
  email: string,
): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

/**
 * Validate that a user exists. Throws if not found.
 * Takes the lookup result — the repository call stays in the service.
 */
export function validateUserExists(
  user: User | undefined,
  userId: string,
): void {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Email validators — pure validation functions for email format.
 *
 * Reusable across services and adapters.
 */

/** Simple email-format check. */
export const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate an email address format.
 * Returns an error message string if invalid, or null if valid.
 */
export function validateEmailFormat(email: string): string | null {
  if (!email) {
    return 'Recipient email is required';
  }
  if (!EMAIL_REGEX.test(email)) {
    return `Invalid email format: ${email}`;
  }
  return null;
}

