import { describe, it, expect } from 'vitest';
import {
  ORDER_STATUS_TRANSITIONS,
  isValidStatusTransition,
  validateStatusTransition,
  validateOrderHasItems,
  validateUserForOrder,
} from '../../src/validators/order.validator.js';
import type { OrderStatus } from '../../src/models/order.js';

describe('Order Validators', () => {
  describe('ORDER_STATUS_TRANSITIONS', () => {
    it('should define transitions for all statuses', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(ORDER_STATUS_TRANSITIONS[status]).toBeDefined();
        expect(Array.isArray(ORDER_STATUS_TRANSITIONS[status])).toBe(true);
      }
    });

    it('should have correct transitions from pending', () => {
      expect(ORDER_STATUS_TRANSITIONS.pending).toEqual(['confirmed', 'cancelled']);
    });

    it('should have correct transitions from confirmed', () => {
      expect(ORDER_STATUS_TRANSITIONS.confirmed).toEqual(['shipped', 'cancelled']);
    });

    it('should have no transitions from terminal states', () => {
      expect(ORDER_STATUS_TRANSITIONS.delivered).toEqual([]);
      expect(ORDER_STATUS_TRANSITIONS.cancelled).toEqual([]);
    });
  });

  describe('isValidStatusTransition', () => {
    it('should return true for valid transitions', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should return false for invalid transitions', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
      expect(isValidStatusTransition('shipped', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
      expect(() => validateStatusTransition('confirmed', 'shipped')).not.toThrow();
      expect(() => validateStatusTransition('shipped', 'delivered')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('cancelled', 'pending')).toThrow(
        'Invalid status transition',
      );
      expect(() => validateStatusTransition('delivered', 'shipped')).toThrow(
        'Invalid status transition',
      );
    });
  });

  describe('validateOrderHasItems', () => {
    it('should not throw for non-empty items', () => {
      expect(() =>
        validateOrderHasItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('validateUserForOrder', () => {
    it('should not throw when user exists', () => {
      expect(() =>
        validateUserForOrder({ id: 'user-1' }, 'user-1'),
      ).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserForOrder(undefined, 'user-99')).toThrow(
        'User not found: user-99',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailNotTaken,
  validateEmailNotInUse,
  validateUserExists,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const mockUser: User = {
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('User Validators', () => {
  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user', () => {
      expect(() => validateEmailNotTaken(undefined, 'new@example.com')).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      expect(() => validateEmailNotTaken(mockUser, 'alice@example.com')).toThrow(
        'User with email alice@example.com already exists',
      );
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should not throw when no existing user', () => {
      expect(() => validateEmailNotInUse(undefined, 'new@example.com')).not.toThrow();
    });

    it('should throw when email is in use', () => {
      expect(() => validateEmailNotInUse(mockUser, 'alice@example.com')).toThrow(
        'Email alice@example.com is already in use',
      );
    });
  });

  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      expect(() => validateUserExists(mockUser, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { EMAIL_REGEX, validateEmailFormat } from '../../src/validators/email.validator.js';

describe('Email Validators', () => {
  describe('EMAIL_REGEX', () => {
    it('should match valid emails', () => {
      expect(EMAIL_REGEX.test('user@example.com')).toBe(true);
      expect(EMAIL_REGEX.test('first.last@domain.org')).toBe(true);
      expect(EMAIL_REGEX.test('user+tag@sub.domain.com')).toBe(true);
    });

    it('should reject invalid emails', () => {
      expect(EMAIL_REGEX.test('')).toBe(false);
      expect(EMAIL_REGEX.test('not-an-email')).toBe(false);
      expect(EMAIL_REGEX.test('@domain.com')).toBe(false);
      expect(EMAIL_REGEX.test('user@')).toBe(false);
      expect(EMAIL_REGEX.test('user @domain.com')).toBe(false);
    });
  });

  describe('validateEmailFormat', () => {
    it('should return null for valid emails', () => {
      expect(validateEmailFormat('user@example.com')).toBeNull();
      expect(validateEmailFormat('alice@test.org')).toBeNull();
    });

    it('should return error for empty email', () => {
      expect(validateEmailFormat('')).toBe('Recipient email is required');
    });

    it('should return error for invalid format', () => {
      const result = validateEmailFormat('not-an-email');
      expect(result).toBe('Invalid email format: not-an-email');
    });

    it('should return error for email with spaces', () => {
      const result = validateEmailFormat('user @example.com');
      expect(result).toBe('Invalid email format: user @example.com');
    });
  });
});

